/**
 * Naga Hanuma Portfolio - 3D AI Chat Agent Integration
 * Language: JavaScript (Vanilla ES6)
 * Uses: Three.js (via CDN) for 3D rendering
 */

document.addEventListener('DOMContentLoaded', () => {
    // API endpoint config: Automatically uses localhost for local testing, otherwise falls back to production Render URL
    const BACKEND_URL = (window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1')
        ? 'http://localhost:10000/api/chat'
        : 'https://portfolio-backend-twmb.onrender.com/api/chat';
    
    // UI Elements
    const agentContainer = document.getElementById('ai-agent-container');
    const canvasContainer = document.getElementById('avatar-canvas-container');
    const chatToggleBtn = document.getElementById('chat-toggle-btn');
    const chatCloseBtn = document.getElementById('chat-close-btn');
    const chatInput = document.getElementById('chat-input');
    const chatForm = document.getElementById('chat-form');
    const chatMessages = document.getElementById('chat-messages');

    if (!agentContainer || !canvasContainer) {
        console.error("AI Agent UI elements not found in DOM.");
        return;
    }

    // -----------------------------------------------------------------
    // THREE.JS SCENE SETUP
    // -----------------------------------------------------------------
    let scene, camera, renderer, avatarGroup, headGroup;
    let trackingNode = null;
    let gltfModel = null;
    let proceduralDroneGroup = null;
    let orbitRing1 = null, orbitRing2 = null;
    let mouse = { x: 0, y: 0 };
    let targetHeadRotation = { x: 0, y: 0 };
    let isInputFocused = false;
    let clock = new THREE.Clock();

    function init3D() {
        // Create canvas
        const canvas = document.createElement('canvas');
        canvas.id = 'avatar-canvas';
        canvasContainer.appendChild(canvas);

        // Scene
        scene = new THREE.Scene();

        // Camera
        camera = new THREE.PerspectiveCamera(45, canvasContainer.clientWidth / canvasContainer.clientHeight, 0.1, 100);
        camera.position.set(0, 0.1, 3.2);

        // Renderer
        renderer = new THREE.WebGLRenderer({ canvas: canvas, antialias: true, alpha: true });
        renderer.setSize(canvasContainer.clientWidth, canvasContainer.clientHeight);
        renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
        renderer.shadowMap.enabled = true;

        // Lights
        // Subtle purple or periwinkle ambient light to blend with gradients
        const ambientLight = new THREE.AmbientLight(0xa78bfa, 0.7); 
        scene.add(ambientLight);

        // Main bright white directional light from the front-right-top to make details visible
        const mainLight = new THREE.DirectionalLight(0xffffff, 1.5);
        mainLight.position.set(1.5, 3.0, 3.0);
        scene.add(mainLight);

        // Neon cyan spotlight pointing at avatar for sleek cyber glow highlights
        const spotLight = new THREE.SpotLight(0x00e5ff, 2.5);
        spotLight.position.set(2, 4, 3);
        spotLight.angle = 0.5;
        spotLight.penumbra = 0.5;
        scene.add(spotLight);

        // Purple rim light for cyberpunk edge highlighting
        const backLight = new THREE.DirectionalLight(0x8b5cf6, 1.5);
        backLight.position.set(-2, 2, -2);
        scene.add(backLight);

        // Crisp icy blue rim light positioned behind and slightly above the model for silhouette separation
        const rimLight = new THREE.DirectionalLight(0xE0F2FE, 3.5);
        rimLight.position.set(0, 5, -5);
        scene.add(rimLight);

        // Subtle fill light
        const fillLight = new THREE.DirectionalLight(0xffffff, 0.3);
        fillLight.position.set(-1.5, 0, 1.5);
        scene.add(fillLight);

        // Build Avatar
        buildRobotAvatar();

        // Resize observer to handle container size changes smoothly (especially during CSS transitions)
        const resizeObserver = new ResizeObserver(entries => {
            for (let entry of entries) {
                const width = entry.contentRect.width || canvasContainer.clientWidth;
                const height = entry.contentRect.height || canvasContainer.clientHeight;
                if (width > 0 && height > 0) {
                    renderer.setSize(width, height);
                    camera.aspect = width / height;
                    camera.updateProjectionMatrix();
                }
            }
        });
        resizeObserver.observe(canvasContainer);

        // Event listeners
        window.addEventListener('mousemove', onMouseMove);
        
        if (chatInput) {
            chatInput.addEventListener('focus', () => { isInputFocused = true; });
            chatInput.addEventListener('blur', () => { isInputFocused = false; });
        }

        // Start animation loop
        animate();
    }

    // -----------------------------------------------------------------
    // AVATAR CREATION (Sleek Procedural Cyber-Drone with GLB Model Loader)
    // -----------------------------------------------------------------
    let cyanGlowMat, purpleGlowMat, bodyMat;

    function buildRobotAvatar() {
        avatarGroup = new THREE.Group();
        
        // --- 1. DEFINE MATERIALS ---
        
        // Base Body: Brushed platinum / light silver (#D1D5DB) to pop against dark backgrounds
        bodyMat = new THREE.MeshStandardMaterial({
            color: 0xD1D5DB,
            roughness: 0.6,
            metalness: 0.5,
            bumpScale: 0.05
        });
        
        const darkMetalMat = new THREE.MeshStandardMaterial({
            color: 0x9ca3af, // Slightly darker brushed metal accents
            roughness: 0.5,
            metalness: 0.6
        });

        // Glowing Accents: Emissive neon cyan (#00e5ff) with high intensity
        cyanGlowMat = new THREE.MeshStandardMaterial({
            color: 0x00e5ff,
            emissive: 0x00e5ff,
            emissiveIntensity: 3.0,
            roughness: 0.1
        });

        // Secondary Glow: Emissive purple/magenta for accents
        purpleGlowMat = new THREE.MeshStandardMaterial({
            color: 0x8b5cf6,
            emissive: 0x8b5cf6,
            emissiveIntensity: 1.8,
            roughness: 0.2
        });

                // --- 2. CREATE PROCEDURAL CYBER-DRONE (FALLBACK) ---
        proceduralDroneGroup = new THREE.Group();
        
        // Load the generated AI agent orb logo texture
        const textureLoader = new THREE.TextureLoader();
        const logoTexture = textureLoader.load('data:image/jpeg;base64,');
        
        // 1. Main 3D Sphere Body (Brushed Platinum)
        const sphereGeom = new THREE.SphereGeometry(0.38, 32, 32);
        const sphereMesh = new THREE.Mesh(sphereGeom, bodyMat);
        proceduralDroneGroup.add(sphereMesh);
        
        // 2. Horizontal and Vertical Panel Bands (gives mechanical paneled detail)
        const bandHorizGeom = new THREE.TorusGeometry(0.382, 0.015, 8, 64);
        bandHorizGeom.rotateX(Math.PI / 2);
        const bandHoriz = new THREE.Mesh(bandHorizGeom, darkMetalMat);
        proceduralDroneGroup.add(bandHoriz);
        
        const bandVertGeom = new THREE.TorusGeometry(0.382, 0.015, 8, 64);
        bandVertGeom.rotateY(Math.PI / 2);
        const bandVert = new THREE.Mesh(bandVertGeom, darkMetalMat);
        proceduralDroneGroup.add(bandVert);
        
        // 3. Central Visor / Holographic Screen on front
        // Visor glass backing bezel (cylinder projecting from the sphere surface)
        const visorBackGeom = new THREE.CylinderGeometry(0.24, 0.24, 0.15, 32);
        visorBackGeom.rotateX(Math.PI / 2);
        const visorBack = new THREE.Mesh(visorBackGeom, darkMetalMat);
        visorBack.position.set(0, 0, 0.30); // Positioned on front curve of sphere
        proceduralDroneGroup.add(visorBack);
        
        // Glowing cyan ring framing the visor screen
        const visorGlowRingGeom = new THREE.TorusGeometry(0.242, 0.008, 8, 64);
        const visorGlowRing = new THREE.Mesh(visorGlowRingGeom, cyanGlowMat);
        visorGlowRing.position.set(0, 0, 0.376);
        proceduralDroneGroup.add(visorGlowRing);
        
        // Crop/Zoom texture to display ONLY the eye core
        const visorTexture = logoTexture.clone();
        visorTexture.repeat.set(0.5, 0.5);
        visorTexture.offset.set(0.25, 0.25);
        visorTexture.needsUpdate = true;
        
        const visorScreenGeom = new THREE.CircleGeometry(0.23, 32);
        const visorScreenMat = new THREE.MeshBasicMaterial({
            map: visorTexture,
            transparent: false,
            side: THREE.DoubleSide
        });
        const visorScreen = new THREE.Mesh(visorScreenGeom, visorScreenMat);
        visorScreen.position.set(0, 0, 0.376); // Placed on the face of the cylinder
        proceduralDroneGroup.add(visorScreen);
        
        // 4. Elegant Outer Orbiting Rings (with additive soft glow shell)
        // Orbiting Ring 1 (Neon Cyan)
        const ring1Geom = new THREE.TorusGeometry(0.58, 0.016, 16, 100);
        orbitRing1 = new THREE.Mesh(ring1Geom, cyanGlowMat);
        orbitRing1.rotation.set(0.4, 0.7, 0);
        
        // Volumetric Glow Shell 1 (larger, semi-transparent, additive blending)
        const glowShellMat1 = new THREE.MeshBasicMaterial({
            color: 0x00e5ff,
            transparent: true,
            opacity: 0.35,
            blending: THREE.AdditiveBlending,
            side: THREE.DoubleSide
        });
        const glowShell1 = new THREE.Mesh(new THREE.TorusGeometry(0.58, 0.045, 16, 100), glowShellMat1);
        orbitRing1.add(glowShell1);
        proceduralDroneGroup.add(orbitRing1);
        
        // Orbiting Ring 2 (Neon Violet/Purple)
        const ring2Geom = new THREE.TorusGeometry(0.58, 0.016, 16, 100);
        orbitRing2 = new THREE.Mesh(ring2Geom, purpleGlowMat);
        orbitRing2.rotation.set(-0.4, 0.7, 0);
        
        // Volumetric Glow Shell 2 (larger, semi-transparent, additive blending)
        const glowShellMat2 = new THREE.MeshBasicMaterial({
            color: 0x8b5cf6,
            transparent: true,
            opacity: 0.3,
            blending: THREE.AdditiveBlending,
            side: THREE.DoubleSide
        });
        const glowShell2 = new THREE.Mesh(new THREE.TorusGeometry(0.58, 0.045, 16, 100), glowShellMat2);
        orbitRing2.add(glowShell2);
        proceduralDroneGroup.add(orbitRing2);
        
        // 5. Add subtle lateral mini thruster lights
        const thrusterL = new THREE.Mesh(new THREE.CylinderGeometry(0.02, 0.02, 0.08, 16), bodyMat);
        thrusterL.position.set(-0.55, 0, -0.05);
        thrusterL.rotation.z = Math.PI / 2;
        proceduralDroneGroup.add(thrusterL);
        
        const thrusterR = thrusterL.clone();
        thrusterR.position.x = 0.55;
        proceduralDroneGroup.add(thrusterR);

        const glowL = new THREE.Mesh(new THREE.SphereGeometry(0.018, 16, 16), purpleGlowMat);
        glowL.position.set(-0.60, 0, -0.05);
        proceduralDroneGroup.add(glowL);

        const glowR = glowL.clone();
        glowR.position.x = 0.60;
        proceduralDroneGroup.add(glowR);

        avatarGroup.add(proceduralDroneGroup);
        
        // Set tracking node to proceduralDroneGroup initially so the entire card tilts and tracks the cursor!
        trackingNode = proceduralDroneGroup;
        
        // Position whole avatar in scene
        avatarGroup.position.set(0, -0.1, 0);
        scene.add(avatarGroup);
        
        // --- 3. MODEL LOADING VIA GLTFLOADER ---
        
        // Boilerplate to load GLTF/GLB model
        if (typeof THREE.GLTFLoader !== 'undefined') {
            const loader = new THREE.GLTFLoader();
            // Default model file location (User can drop their cyber_drone.glb here)
            const modelPath = 'assets/models/cyber_drone.glb';
            
            loader.load(
                modelPath,
                (gltf) => {
                    console.log('3D GLTF Model loaded successfully:', modelPath);
                    gltfModel = gltf.scene;
                    
                    // Scale and position the loaded model appropriately
                    gltfModel.scale.set(0.65, 0.65, 0.65);
                    gltfModel.position.set(0, -0.1, 0);
                    
                    // Override materials to match custom theme
                    gltfModel.traverse((node) => {
                        if (node.isMesh) {
                            node.castShadow = true;
                            node.receiveShadow = true;
                            
                            // Override only standard materials to not break specific loaded meshes
                            if (node.material) {
                                const matName = node.material.name ? node.material.name.toLowerCase() : '';
                                const meshName = node.name ? node.name.toLowerCase() : '';
                                
                                // Check if this material is emissive or an accent
                                const isGlowing = matName.includes('glow') || 
                                                 matName.includes('eye') || 
                                                 matName.includes('light') || 
                                                 matName.includes('accent') ||
                                                 meshName.includes('eye') ||
                                                 meshName.includes('glow') ||
                                                 (node.material.emissive && 
                                                  (node.material.emissive.r > 0 || 
                                                   node.material.emissive.g > 0 || 
                                                   node.material.emissive.b > 0));
                                
                                if (isGlowing) {
                                    // High intensity neon cyan glow for accents/eyes
                                    node.material = new THREE.MeshStandardMaterial({
                                        color: 0x00e5ff,
                                        emissive: 0x00e5ff,
                                        emissiveIntensity: 3.5,
                                        roughness: 0.1,
                                        metalness: 0.1
                                    });
                                } else {
                                    // Brushed platinum / light silver base body
                                    node.material = new THREE.MeshStandardMaterial({
                                        color: 0xD1D5DB,
                                        roughness: 0.6,
                                        metalness: 0.5
                                    });
                                }
                            }
                        }
                    });
                    
                    // Locate head/neck tracking node
                    let loadedTrackingNode = null;
                    gltfModel.traverse((child) => {
                        const name = child.name ? child.name.toLowerCase() : '';
                        if (name.includes('head') || name.includes('neck') || name.includes('eye') || name.includes('visor') || name.includes('core')) {
                            // Prioritize head or eye
                            if (!loadedTrackingNode || name.includes('head') || name.includes('eye')) {
                                loadedTrackingNode = child;
                            }
                        }
                    });
                    
                    if (loadedTrackingNode) {
                        trackingNode = loadedTrackingNode;
                    } else {
                        trackingNode = gltfModel;
                    }
                    
                    // Hide the procedural fallback drone
                    proceduralDroneGroup.visible = false;
                    
                    // Add loaded model to avatarGroup
                    avatarGroup.add(gltfModel);
                },
                (xhr) => {
                    if (xhr.total > 0) {
                        console.log(`Loading 3D model: ${Math.round((xhr.loaded / xhr.total * 100))}%`);
                    }
                },
                (error) => {
                    console.warn('Could not load custom GLTF model (using sleek procedural Cyber-Drone fallback):', error.message);
                    console.log('To load your custom model, place a cyber_drone.glb file inside the portfolio/assets/models/ directory.');
                }
            );
        } else {
            console.warn('THREE.GLTFLoader is not defined. Make sure the CDN script is loaded.');
        }
    }

    // -----------------------------------------------------------------
    // ANIMATION & INTERACTION
    // -----------------------------------------------------------------
    function onMouseMove(event) {
        // Normalize mouse coordinates (-1 to 1)
        mouse.x = (event.clientX / window.innerWidth) * 2 - 1;
        mouse.y = -(event.clientY / window.innerHeight) * 2 + 1;
    }

    function animate() {
        requestAnimationFrame(animate);

        const time = clock.getElapsedTime();

        // 1. Idle Floating & Breathing Effects
        if (avatarGroup) {
            avatarGroup.position.y = -0.1 + Math.sin(time * 1.5) * 0.04;
            
            // If GLTF model is active, do a subtle float rotation
            if (gltfModel && gltfModel.visible) {
                gltfModel.rotation.y = Math.sin(time * 0.5) * 0.05;
            } else if (proceduralDroneGroup && proceduralDroneGroup.visible) {
                // Subtle breathing scale on procedural drone
                proceduralDroneGroup.scale.set(
                    1 + Math.sin(time * 1.5) * 0.015,
                    1 + Math.sin(time * 1.5) * 0.01,
                    1 + Math.sin(time * 1.5) * 0.015
                );
            }
        }

        // 2. Rotate Orbiting Rings for procedural drone
        if (proceduralDroneGroup && proceduralDroneGroup.visible && orbitRing1 && orbitRing2) {
            orbitRing1.rotation.z = time * 0.8;
            orbitRing1.rotation.x = time * 0.4;
            
            orbitRing2.rotation.y = -time * 0.6;
            orbitRing2.rotation.z = time * 0.3;
        }
        
        // Emissive light pulse
        if (cyanGlowMat && purpleGlowMat) {
            cyanGlowMat.emissiveIntensity = 2.5 + Math.sin(time * 4) * 0.5;
            purpleGlowMat.emissiveIntensity = 1.5 + Math.cos(time * 3) * 0.3;
        }

        // 3. Head/Node Rotation (Look-at behavior)
        if (trackingNode) {
            if (isInputFocused) {
                // Focus: look slightly down and forward
                targetHeadRotation.x = 0.38; // Tilt down
                targetHeadRotation.y = 0.0;  // Center
            } else {
                // Mouse tracking: limit rotation range
                targetHeadRotation.x = -mouse.y * 0.35; // Vertical tilt
                targetHeadRotation.y = mouse.x * 0.55;  // Horizontal turn
                
                // Add soft nodding/breathing motion to head
                targetHeadRotation.x += Math.sin(time * 0.8) * 0.02;
            }

            // Smooth interpolation (lerp)
            trackingNode.rotation.x += (targetHeadRotation.x - trackingNode.rotation.x) * 0.08;
            trackingNode.rotation.y += (targetHeadRotation.y - trackingNode.rotation.y) * 0.08;
        }

        renderer.render(scene, camera);
    }

    // -----------------------------------------------------------------
    // CHAT PANEL LOGIC & STATE TRANSITIONS
    // -----------------------------------------------------------------
    
    // Toggle Chat Panel Open
    if (chatToggleBtn) {
        chatToggleBtn.addEventListener('click', () => {
            agentContainer.classList.add('chat-active');
            chatInput.focus();
            
            // Auto scroll messages to bottom
            scrollToBottom();
        });
    }

    // Close Chat Panel
    if (chatCloseBtn) {
        chatCloseBtn.addEventListener('click', () => {
            agentContainer.classList.remove('chat-active');
            chatInput.blur();
        });
    }

    // Handle Form Submit (Sending messages)
    if (chatForm) {
        chatForm.addEventListener('submit', async (e) => {
            e.preventDefault();
            
            const messageText = chatInput.value.trim();
            if (!messageText) return;

            // Clear input
            chatInput.value = '';

            // Add User message
            appendMessage(messageText, 'user');

            // Add typing indicator
            const typingIndicator = appendTypingIndicator();
            scrollToBottom();

            try {
                // Asynchronous fetch call to backend API
                const response = await fetch(BACKEND_URL, {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json'
                    },
                    body: JSON.stringify({ message: messageText })
                });

                // Remove typing indicator
                removeTypingIndicator(typingIndicator);

                if (!response.ok) {
                    let errorMessage = "";
                    try {
                        const errorData = await response.json();
                        errorMessage = errorData.detail || "";
                    } catch (e) {}

                    const lowerMessage = errorMessage.toLowerCase();
                    if (response.status === 429 || 
                        lowerMessage.includes("quota") || 
                        lowerMessage.includes("limit") || 
                        lowerMessage.includes("exceeded") ||
                        lowerMessage.includes("429")) {
                        appendMessage(
                            "I have completed my daily quota limit for today. Please try again later or check back tomorrow!",
                            'agent error-message'
                        );
                    } else {
                        appendMessage(
                            `Server Error: ${errorMessage || response.statusText || 'Internal Server Error'}. Please check backend logs.`,
                            'agent error-message'
                        );
                    }
                    scrollToBottom();
                    return;
                }

                const data = await response.json();
                appendMessage(data.response, 'agent');

            } catch (error) {
                console.error("Failed to fetch response from backend:", error);
                
                // Remove typing indicator
                removeTypingIndicator(typingIndicator);
                
                // Display error message to user
                appendMessage(
                    "Connection lost! Please make sure Naga's backend server is running locally on port 10000.", 
                    'agent error-message'
                );
            }

            scrollToBottom();
        });
    }

    // Helper: Append Message Bubble to UI
    function appendMessage(text, sender) {
        const messageDiv = document.createElement('div');
        messageDiv.className = `chat-message ${sender}`;
        
        const bubble = document.createElement('div');
        bubble.className = 'message-bubble';
        bubble.textContent = text;
        
        messageDiv.appendChild(bubble);
        chatMessages.appendChild(messageDiv);
    }

    // Helper: Add Typing Indicator
    function appendTypingIndicator() {
        const indicatorDiv = document.createElement('div');
        indicatorDiv.className = 'chat-message agent typing-indicator-container';
        
        const bubble = document.createElement('div');
        bubble.className = 'message-bubble typing-bubble';
        
        // Create 3 blinking dots
        for (let i = 0; i < 3; i++) {
            const dot = document.createElement('span');
            dot.className = 'typing-dot';
            bubble.appendChild(dot);
        }
        
        indicatorDiv.appendChild(bubble);
        chatMessages.appendChild(indicatorDiv);
        return indicatorDiv;
    }

    // Helper: Remove Typing Indicator
    function removeTypingIndicator(indicatorElement) {
        if (indicatorElement && indicatorElement.parentNode) {
            indicatorElement.parentNode.removeChild(indicatorElement);
        }
    }

    // Helper: Auto-scroll Messages Body
    function scrollToBottom() {
        chatMessages.scrollTop = chatMessages.scrollHeight;
    }

    // Initialize the Three.js canvas once everything is loaded
    init3D();
});
